import React, { useState } from "react";
import Marquee from "react-fast-marquee";
import img1 from "./images/01.png";
import img2 from "./images/02.png";
import img3 from "./images/03.png";
import "./App.css";
import ReactTooltip from 'react-tooltip';


function MarqueeExample() {
  const [tooltipContent, setTooltipContent] = useState("");

  function handleClick(imageIndex) {
    switch (imageIndex) {
      case 0:
        window.location.href = "page1.html";
        break;
      case 1:
        window.location.href = "page2.html";
        break;
      case 2:
        window.location.href = "page3.html";
        break;
      default:
        break;
    }
  }

  return (
    <div className="marquee-container">
      <Marquee gradient={false} speed={40} direction="up">
        <div
          className="marquee-item"
          onClick={() => handleClick(0)}
          onMouseEnter={() => setTooltipContent("Click to learn more")}
          onMouseLeave={() => setTooltipContent("")}
        >
          <div className="marquee-item-box">
            <img
              src={img1}
              alt="example"
              data-tip={tooltipContent}
              data-for="tooltip-img-1"
            />
            <ReactTooltip id="tooltip-img-1" effect="solid" place="right" />
            <span>Lorem ipsum dolor sit amet, consectetur adipiscing elit.</span>
          </div>
        </div>
        <div
          className="marquee-item"
          onClick={() => handleClick(1)}
          onMouseEnter={() =>
            setTooltipContent("Click to learn more about Sed")
          }
          onMouseLeave={() => setTooltipContent("")}
        >
          <div className="marquee-item-box">
            <img
              src={img2}
              alt="example"
              data-tip={tooltipContent}
              data-for="tooltip-img-2"
            />
            <ReactTooltip id="tooltip-img-2" effect="solid" place="right" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
          </div>
        </div>
        <div
          className="marquee-item"
          onClick={() => handleClick(2)}
          onMouseEnter={() =>
            setTooltipContent("Click to learn more about magna aliqua")
          }
          onMouseLeave={() => setTooltipContent("")}
        >
          <div className="marquee-item-box">
            <img
              src={img3}
              alt="example"
              data-tip={tooltipContent}
              data-for="tooltip-img-3"
            />
            <ReactTooltip id="tooltip-img-3" effect="solid" place="right" />
            <span>
              Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.
            </span>
          </div>
        </div>
      </Marquee>
    </div>
  );
}

export default MarqueeExample;
